(function($){$(document).ready(function(){var $banner=$(".charitable-external-banner");if(!$banner.length){return}var $target=$("#wpbody-content").children('[id^="give-admin-"], [id="reports-app"], .wrap').first();if($target.length){$banner.detach().insertBefore($target)}else{$banner.detach().prependTo("#wpbody-content")}var bannerId=$banner.data("banner-id");var seenKey="charitable-ext-banner-"+bannerId+"-seen";if(window.localStorage.getItem(seenKey)){$banner.show()}else{setTimeout(function(){window.localStorage.setItem(seenKey,true);$banner.slideDown(300)},800)}$banner.on("click",".charitable-external-banner-dismiss",function(e){e.preventDefault();var nonce=$banner.data("nonce");$.ajax({type:"POST",url:charitable_external_banner.ajaxurl,data:{action:"charitable_dismiss_external_banner",banner_id:bannerId,nonce:nonce},dataType:"json",success:function(){$banner.slideUp("fast",function(){$banner.remove()});window.localStorage.removeItem(seenKey)}})})})})(jQuery);